FUNCTION_BLOCK FB_CalculateDayOfYear
VAR_INPUT
    Year : INT;
    Month : INT;
    Day : INT;
END_VAR
VAR_OUTPUT
    DayOfYear : INT;
    error : BOOL;
    status : WORD;
END_VAR
VAR_TEMP
    i : INT;
    isLeapYear : BOOL;
    maxDay : INT;
END_VAR
VAR
    DaysInMonth : ARRAY[1..12] OF INT := [31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];
END_VAR

(* Initialize outputs *)
DayOfYear := 0;
error := FALSE;
status := 0;

(* 1. Month validation (highest priority) *)
IF (Month < 1) OR (Month > 12) THEN
    error := TRUE;
    status := 16#8002;  (* Invalid month *)
    RETURN;
END_IF;

(* 2. Day validation (second priority) *)
(* First check if day is positive *)
IF Day <= 0 THEN
    error := TRUE;
    status := 16#8003;  (* Invalid day *)
    RETURN;
END_IF;

(* Determine leap year status *)
isLeapYear := ((Year MOD 4 = 0) AND (Year MOD 100 <> 0)) OR (Year MOD 400 = 0);

(* Get maximum days for the month *)
maxDay := DaysInMonth[Month];
IF (Month = 2) AND isLeapYear THEN
    maxDay := 29;
END_IF;

(* Check if day exceeds maximum for the month *)
IF Day > maxDay THEN
    error := TRUE;
    status := 16#8003;  (* Invalid day *)
    RETURN;
END_IF;

(* 3. Year validation (lowest priority) *)
IF (Year < 1000) OR (Year > 3000) THEN
    error := TRUE;
    status := 16#8001;  (* Invalid year *)
    RETURN;
END_IF;

(* All inputs valid - calculate day of year *)
FOR i := 1 TO (Month - 1) DO
    DayOfYear := DayOfYear + DaysInMonth[i];
END_FOR;

DayOfYear := DayOfYear + Day;

(* Add extra day for leap years if month is after February *)
IF isLeapYear AND (Month > 2) THEN
    DayOfYear := DayOfYear + 1;
END_IF;

END_FUNCTION_BLOCK

FUNCTION_BLOCK SelectSort
VAR_INPUT
    exe : BOOL;
    seq : ARRAY[1..100] OF INT;
END_VAR
VAR_OUTPUT
    error : BOOL;
    status : WORD;
END_VAR
VAR
    i : INT;
    j : INT;
    min_idx : INT;
    temp : INT;
    n : INT := 100;
    seq_local : ARRAY[1..100] OF INT;
    sort_successful : BOOL;
END_VAR

IF exe THEN
    // Initialize outputs
    error := FALSE;
    status := 16#0000;
    sort_successful := TRUE;

    // Copy input array to local working array
    FOR i := 1 TO n DO
        seq_local[i] := seq[i];
    END_FOR;

    // Selection sort algorithm
    FOR i := 1 TO n-1 DO
        min_idx := i;
        FOR j := i+1 TO n DO
            IF seq_local[j] < seq_local[min_idx] THEN
                min_idx := j;
            END_IF;
        END_FOR;

        // Swap elements if needed
        IF min_idx <> i THEN
            temp := seq_local[i];
            seq_local[i] := seq_local[min_idx];
            seq_local[min_idx] := temp;
        END_IF;
    END_FOR;

    // Copy sorted array back to output
    FOR i := 1 TO n DO
        seq[i] := seq_local[i];
    END_FOR;

    // Verify sorting was successful
    FOR i := 1 TO n-1 DO
        IF seq[i] > seq[i+1] THEN
            sort_successful := FALSE;
            EXIT;
        END_IF;
    END_FOR;

    // Set error status if verification failed
    IF NOT sort_successful THEN
        error := TRUE;
        status := 16#8A01;
    END_IF;
END_IF;

END_FUNCTION_BLOCK

