    // Pre-calculated slopes for each segment for efficiency
    Slope1 : REAL := (240.0 - 150.0) / (3600.0 - 1200.0); // 90/2400
    Slope2 : REAL := (560.0 - 240.0) / (4800.0 - 3600.0); // 320/1200
    Slope3 : REAL := (720.0 - 560.0) / (7000.0 - 4800.0); // 160/2200
END_VAR

// Main execution logic
IF InputValue < InputMin THEN
    // Below minimum range
    LinearizedValue := OutputMin;
    Error := TRUE;
    Status := 16#8001;
ELSIF InputValue > InputMax THEN
    // Above maximum range
    LinearizedValue := OutputMax;
    Error := TRUE;
    Status := 16#8001;
ELSE
    // Input is within valid range
    Error := FALSE;
    Status := 16#0000;

    // Determine which segment the input falls into
    IF InputValue <= 3600.0 THEN
        // Range 1: 1200 to 3600
        LinearizedValue := 150.0 + (InputValue - 1200.0) * Slope1;
    ELSIF InputValue <= 4800.0 THEN
        // Range 2: 3600 to 4800
        LinearizedValue := 240.0 + (InputValue - 3600.0) * Slope2;
    ELSE
        // Range 3: 4800 to 7000
        LinearizedValue := 560.0 + (InputValue - 4800.0) * Slope3;
    END_IF;
END_IF;

END_FUNCTION_BLOCK

FUNCTION_BLOCK FB_WarehouseManagement
VAR_INPUT
    requestIn : BOOL := FALSE;
    requestOut : BOOL := FALSE;
END_VAR

VAR_OUTPUT
    productNum : INT := 0;
    libFreeNum : INT := 9;
    error : BOOL := FALSE;
    status : WORD := 16#0000;
END_VAR

VAR_IN_OUT
    library : ARRAY[1..9] OF BOOL;
END_VAR

VAR
    i : INT;
    found : BOOL;
    errFull : WORD := 16#8001;
    errEmpty : WORD := 16#8002;
    initDone : BOOL := FALSE;
END_VAR

// Reset error status at start of each cycle
error := FALSE;
status := 16#0000;

// Initialize library array on first execution
IF NOT initDone THEN
    i := 1;
    WHILE i <= 9 DO
        library[i] := FALSE;
        i := i + 1;
    END_WHILE;
    initDone := TRUE;
END_IF;

// Handle product storage request
IF requestIn AND NOT requestOut THEN
    // Check if storage is full
    IF productNum >= 9 THEN
        error := TRUE;
        status := errFull;
    ELSE
        // Search for free position from highest to lowest index (First-In-Last-Out)
        found := FALSE;
        i := 9;
        WHILE i >= 1 AND NOT found DO
            IF NOT library[i] THEN
                library[i] := TRUE;
                productNum := productNum + 1;
                libFreeNum := libFreeNum - 1;
                found := TRUE;
            END_IF;
            i := i - 1;
        END_WHILE;

        // If no free position found (should not happen with proper checks)
        IF NOT found THEN
            error := TRUE;
            status := errFull;
        END_IF;
    END_IF;
END_IF;

// Handle product retrieval request
IF requestOut AND NOT requestIn THEN
    // Check if storage is empty
    IF productNum <= 0 THEN
        error := TRUE;
        status := errEmpty;
    ELSE
        // Search for occupied position from lowest to highest index (First-In-First-Out)
        found := FALSE;
        i := 1;
        WHILE i <= 9 AND NOT found DO
            IF library[i] THEN
                library[i] := FALSE;
                productNum := productNum - 1;
                libFreeNum := libFreeNum + 1;
                found := TRUE;
            END_IF;
            i := i + 1;
        END_WHILE;

        // If no occupied position found (should not happen with proper checks)
        IF NOT found THEN
            error := TRUE;
            status := errEmpty;
        END_IF;
    END_IF;
END_IF;

// Handle concurrent requests (both true) - prioritize storage
IF requestIn AND requestOut THEN
    // Check if storage is full for storage operation
    IF productNum >= 9 THEN
        error := TRUE;
        status := errFull;
    ELSE
        // Perform storage operation (same logic as above)
        found := FALSE;
        i := 9;
        WHILE i >= 1 AND NOT found DO
            IF NOT library[i] THEN
                library[i] := TRUE;
                productNum := productNum + 1;
                libFreeNum := libFreeNum - 1;
                found := TRUE;
            END_IF;
            i := i - 1;
        END_WHILE;

        IF NOT found THEN
            error := TRUE;
            status := errFull;
        END_IF;
    END_IF;
END_IF;

END_FUNCTION_BLOCK

FUNCTION_BLOCK FB_ColorLightControl
VAR_INPUT
    controlButton : BOOL; // Push button for sequence control
END_VAR

VAR_OUTPUT
    greenLight : BOOL; // Green light control signal
    redLight : BOOL; // Red light control signal
    yellowLight : BOOL; // Yellow light control signal
END_VAR

VAR
    state : INT := 1; // State machine control variable
    lastControlButton : BOOL := FALSE; // Previous button state for edge detection
END_VAR

// Main logic
IF (controlButton = TRUE) AND (lastControlButton = FALSE) THEN
    // Rising edge detected - execute state transition
    CASE state OF
        1: // State 1: Green Only -> Transition to State 2
            greenLight := FALSE;
            redLight := TRUE;
            yellowLight := FALSE;
            state := 2;

        2: // State 2: Red Only -> Transition to State 3
            greenLight := FALSE;
            redLight := FALSE;
            yellowLight := TRUE;
            state := 3;

        3: // State 3: Yellow Only -> Transition to State 4
            greenLight := TRUE;
            redLight := TRUE;
            yellowLight := TRUE;
            state := 4;

        4: // State 4: All Lights On -> Transition to State 5
            greenLight := FALSE;
            redLight := FALSE;
            yellowLight := FALSE;
            state := 5;

        5: // State 5: All Lights Off -> Transition to State 1
            greenLight := TRUE;
            redLight := FALSE;
            yellowLight := FALSE;
            state := 1;
    END_CASE;
ELSE
    // No rising edge - maintain current state outputs
    CASE state OF
        1: // State 1: Green Only
            greenLight := TRUE;
            redLight := FALSE;
            yellowLight := FALSE;

        2: // State 2: Red Only
            greenLight := FALSE;
            redLight := TRUE;
            yellowLight := FALSE;

        3: // State 3: Yellow Only
            greenLight := FALSE;
            redLight := FALSE;
            yellowLight := TRUE;

        4: // State 4: All Lights On
            greenLight := TRUE;
            redLight := TRUE;
            yellowLight := TRUE;

        5: // State 5: All Lights Off
            greenLight := FALSE;
            redLight := FALSE;
            yellowLight := FALSE;
    END_CASE;
END_IF;

// Update lastControlButton for next cycle's edge detection
lastControlButton := controlButton;

END_FUNCTION_BLOCK

FUNCTION_BLOCK FB_DatabaseManager
VAR_INPUT
    dataInput : ARRAY[0..5] OF BYTE;
    storeTrigger : BOOL;
    resetTrigger : BOOL;
END_VAR
VAR_OUTPUT
    usedSpace : INT := 0;
    remainingSpace : INT := 20;
    error : BOOL;
    status : WORD;
END_VAR
VAR_IN_OUT
    dataBase : ARRAY[1..20] OF BYTE;
END_VAR
VAR
    i : INT;
    dataLength : INT;
END_VAR

IF resetTrigger THEN
    (* Reset Operation *)
    FOR i := 1 TO 20 DO
        dataBase[i] := 0;
    END_FOR;
    usedSpace := 0;
    remainingSpace := 20;
    error := FALSE;
    status := 0;
ELSIF storeTrigger THEN
    (* Data Storage Operation *)
    dataLength := dataInput[0];

    (* Length Validation *)
    IF (dataLength <= 0) OR (dataLength > 5) THEN
        error := TRUE;
        status := 16#8001;
    ELSE
        (* Space Verification *)
        IF (usedSpace + dataLength) > 20 THEN
            error := TRUE;
            status := 16#8002;
        ELSE
            (* Data Storage *)
            FOR i := 1 TO dataLength DO
                dataBase[usedSpace + i] := dataInput[i];
            END_FOR;

            (* Update counters *)
            usedSpace := usedSpace + dataLength;
            remainingSpace := 20 - usedSpace;
            error := FALSE;
            status := 0;
        END_IF;
    END_IF;
END_IF;

END_FUNCTION_BLOCK

FUNCTION_BLOCK FB_ProductionLineControl
VAR_INPUT
    Mode : BOOL;           // Manual/Auto mode selection
    ForwardButton : BOOL;  // Forward rotation button
    ReverseButton : BOOL;  // Reverse rotation button
    SensorA : BOOL;        // Sensor A input
    SensorB : BOOL;        // Sensor B input
    SensorC : BOOL;        // Sensor C input
    ButtonA : BOOL;        // Button A input
    ButtonB : BOOL;        // Button B input
    ButtonC : BOOL;        // Button C input
END_VAR

VAR_OUTPUT
    MotorForward : BOOL;   // Motor forward output
    MotorReverse : BOOL;   // Motor reverse output
    CompletionLight : BOOL; // Process completion indicator
END_VAR

VAR
    State : INT;           // State machine current state
END_VAR

// Main logic
IF State = 0 THEN
    // Initialization state
    MotorForward := FALSE;
    MotorReverse := FALSE;
    CompletionLight := FALSE;
    State := 1;
ELSE
    IF NOT Mode THEN
        // Manual mode operation
        IF ForwardButton AND NOT ReverseButton THEN
            // Forward motion
            MotorForward := TRUE;
            MotorReverse := FALSE;
        ELSIF ReverseButton AND NOT ForwardButton THEN
            // Reverse motion
            MotorForward := FALSE;
            MotorReverse := TRUE;
        ELSE
            // Stop condition (both buttons or neither)
            MotorForward := FALSE;
            MotorReverse := FALSE;
        END_IF;

        // Manual mode doesn't use CompletionLight
        CompletionLight := FALSE;
    ELSE
        // Automatic mode operation
        CASE State OF
            1: // Waiting at Station A
                MotorForward := FALSE;
                MotorReverse := FALSE;
                CompletionLight := FALSE;

                IF SensorA THEN
                    State := 2;
                END_IF;

            2: // Processing at Station A
                MotorForward := FALSE;
                MotorReverse := FALSE;

                IF ButtonA THEN
                    MotorForward := TRUE;
                    MotorReverse := FALSE;
                    State := 3;
                END_IF;

            3: // Moving to Station B
                // MotorForward remains TRUE from State 2
                MotorReverse := FALSE;

                IF SensorB THEN
                    MotorForward := FALSE;
                    State := 4;
                END_IF;

            4: // Processing at Station B
                MotorForward := FALSE;
                MotorReverse := FALSE;

                IF ButtonB THEN
                    MotorForward := TRUE;
                    MotorReverse := FALSE;
                    State := 5;
                END_IF;

            5: // Moving to Station C
                // MotorForward remains TRUE from State 4
                MotorReverse := FALSE;

                IF SensorC THEN
                    MotorForward := FALSE;
                    State := 6;
                END_IF;

            6: // Processing at Station C
                MotorForward := FALSE;
                MotorReverse := FALSE;

                IF ButtonC THEN
                    CompletionLight := TRUE;
                    State := 7;
                END_IF;

            7: // Cycle Completion
                MotorForward := FALSE;
                MotorReverse := FALSE;

                IF NOT SensorC THEN
                    CompletionLight := FALSE;
                    State := 1;
                END_IF;

        END_CASE;
    END_IF;
END_IF;

END_FUNCTION_BLOCK

FUNCTION_BLOCK FB_SplitNumber
VAR_INPUT
    InputNumber : INT;
END_VAR

VAR_OUTPUT
    Thousands : INT;
    Hundreds : INT;
    Tens : INT;
    Ones : INT;
    Min : INT;
    error : BOOL;
    status : WORD;
END_VAR

VAR
    tempNumber : INT;
    minValue : INT;
    digit1 : INT;
    digit2 : INT;
    digit3 : INT;
    digit4 : INT;
END_VAR

// Input validation
IF (InputNumber < 0) OR (InputNumber > 9999) THEN
    // Error condition
    error := TRUE;
    status := 16#8001;
    Thousands := 0;
    Hundreds := 0;
    Tens := 0;
    Ones := 0;
    Min := 0;
ELSE
    // Valid input
    error := FALSE;
    status := 0;

    // Digit separation
    Thousands := InputNumber / 1000;
    tempNumber := InputNumber MOD 1000;
    Hundreds := tempNumber / 100;
    tempNumber := tempNumber MOD 100;
    Tens := tempNumber / 10;
    Ones := tempNumber MOD 10;

    // Minimum non-zero digit detection
    minValue := 32767; // Maximum INT value

    // Check Thousands digit
    IF Thousands > 0 THEN
        minValue := minimal(minValue, Thousands);
    END_IF;

    // Check Hundreds digit
    IF Hundreds > 0 THEN
        minValue := minimal(minValue, Hundreds);
    END_IF;

    // Check Tens digit
    IF Tens > 0 THEN
        minValue := minimal(minValue, Tens);
    END_IF;

    // Check Ones digit
    IF Ones > 0 THEN
        minValue := minimal(minValue, Ones);
    END_IF;

    // Set Min output
    IF minValue = 32767 THEN
        // All digits are zero
        Min := 0;
    ELSE
        Min := minValue;
    END_IF;
END_IF;
END_FUNCTION_BLOCK

FUNCTION minimal : INT
VAR_INPUT
    IN1 : INT;
    IN2 : INT;
END_VAR

IF IN1 <= IN2 THEN
    minimal := IN1;
ELSE
    minimal := IN2;
END_IF;
END_FUNCTION

