    ExitGateSensor : BOOL; (* Sensor input for exit gate *)
    CarDetected : BOOL; (* Sensor input for car detection *)
END_VAR
VAR_OUTPUT
    ParkingSpaceNumber : INT := 0; (* Allocated parking space number *)
    RetrievalInProgress : BOOL := FALSE; (* Flag for car retrieval in progress *)
END_VAR
VAR
    ParkingSpaces : ARRAY[1..100] OF BOOL; (* Parking space status: TRUE=Occupied, FALSE=Available *)
    i : INT; (* Loop counter *)
    AssignedSpace : INT := 0; (* Temporary storage for assigned space *)
    RetrievalComplete : BOOL := FALSE; (* Flag to track retrieval completion *)
END_VAR

// Entry Gate Management
IF EntryGateSensor AND NOT RetrievalInProgress THEN
    // Find first available parking space
    AssignedSpace := 0;
    FOR i := 1 TO 100 DO
        IF NOT ParkingSpaces[i] THEN
            AssignedSpace := i;
            EXIT;
        END_IF
    END_FOR

    // If available space found, allocate it
    IF AssignedSpace > 0 THEN
        ParkingSpaces[AssignedSpace] := TRUE;
        ParkingSpaceNumber := AssignedSpace;
    END_IF
END_IF

// Exit Gate Management
IF ExitGateSensor AND (ParkingSpaceNumber > 0) THEN
    // Mark the space as available and reset output
    ParkingSpaces[ParkingSpaceNumber] := FALSE;
    ParkingSpaceNumber := 0;
END_IF

// Car Retrieval Management
IF CarDetected AND NOT RetrievalInProgress AND (ParkingSpaceNumber > 0) THEN
    RetrievalInProgress := TRUE;
    RetrievalComplete := FALSE;
END_IF

IF RetrievalInProgress AND NOT RetrievalComplete THEN
    // Execute car movement to exit gate
    RetrievalComplete := MoveCarToExitGate(ParkingSpaceNumber);

    IF RetrievalComplete THEN
        // Mark space as available and reset
        ParkingSpaces[ParkingSpaceNumber] := FALSE;
        ParkingSpaceNumber := 0;
        RetrievalInProgress := FALSE;
    END_IF
END_IF

END_FUNCTION_BLOCK

FUNCTION_BLOCK BakeryOvenControl
VAR_INPUT
    TemperatureSensor : REAL;           (* Current oven temperature measurement *)
    HumiditySensor : REAL;              (* Current oven humidity measurement *)
    TemperatureSetpoint : REAL := 180.0; (* Desired temperature setpoint *)
    HumiditySetpoint : REAL := 60.0;    (* Desired humidity setpoint *)
    BakingTimeSetpoint : TIME := T#30m; (* Total baking duration *)
    OvenEnable : BOOL;                  (* Master enable signal for oven operation *)
    TemperatureThreshold : REAL := 2.0; (* Temperature control deadband *)
    HumidityThreshold : REAL := 5.0;    (* Humidity control deadband *)
END_VAR

VAR_OUTPUT
    HeatingElement : BOOL;              (* Control output for heating element *)
    CoolingElement : BOOL;              (* Control output for cooling element *)
    HumidityControl : BOOL;             (* Control output for humidification system *)
    DehumidityControl : BOOL;           (* Control output for dehumidification system *)
    BakingComplete : BOOL;              (* Flag indicating baking cycle completion *)
    RemainingTimeDisplay : TIME;        (* Remaining baking time for display *)
END_VAR

VAR
    RemainingTime : TIME;               (* Internal remaining time counter *)
    OneSecTimer : TON;                  (* Timer for one-second intervals *)
    OvenActive : BOOL;                  (* Internal oven active state *)
    StartBaking : BOOL;                 (* Edge detection for baking start *)
    TemperatureLowLimit : REAL;         (* Calculated temperature lower limit *)
    TemperatureHighLimit : REAL;        (* Calculated temperature upper limit *)
    HumidityLowLimit : REAL;            (* Calculated humidity lower limit *)
    HumidityHighLimit : REAL;           (* Calculated humidity upper limit *)
    PrevOvenEnable : BOOL;              (* Previous state for edge detection *)
END_VAR

(* Calculate control limits based on setpoints and thresholds *)
TemperatureLowLimit := TemperatureSetpoint - TemperatureThreshold;
TemperatureHighLimit := TemperatureSetpoint + TemperatureThreshold;
HumidityLowLimit := HumiditySetpoint - HumidityThreshold;
HumidityHighLimit := HumiditySetpoint + HumidityThreshold;

(* Edge detection for oven enable signal *)
StartBaking := OvenEnable AND NOT PrevOvenEnable;
PrevOvenEnable := OvenEnable;

(* Oven state management *)
IF StartBaking THEN
    (* Initialize baking cycle when oven is first enabled *)
    RemainingTime := BakingTimeSetpoint;
    OvenActive := TRUE;
    BakingComplete := FALSE;
ELSIF NOT OvenEnable THEN
    (* Force oven inactive when enable signal is removed *)
    OvenActive := FALSE;
    BakingComplete := FALSE;
END_IF;

(* Timer logic for one-second decrement *)
OneSecTimer(IN := OvenActive, PT := T#1s);

IF OneSecTimer.Q THEN
    (* Decrement remaining time each second *)
    IF RemainingTime > T#0s THEN
        RemainingTime := RemainingTime - T#1s;
    END_IF;

    (* Check for baking completion *)
    IF RemainingTime <= T#0s THEN
        OvenActive := FALSE;
        BakingComplete := TRUE;
    END_IF;
END_IF;

(* Update display output *)
RemainingTimeDisplay := RemainingTime;

(* Temperature control logic - evaluated every scan *)
IF OvenActive AND (RemainingTime > T#0s) THEN
    (* Heating control *)
    IF TemperatureSensor < TemperatureLowLimit THEN
        HeatingElement := TRUE;
        CoolingElement := FALSE;
    (* Cooling control *)
    ELSIF TemperatureSensor > TemperatureHighLimit THEN
        HeatingElement := FALSE;
        CoolingElement := TRUE;
    (* Within acceptable range *)
    ELSE
        HeatingElement := FALSE;
        CoolingElement := FALSE;
    END_IF;

    (* Humidity control *)
    IF HumiditySensor < HumidityLowLimit THEN
        HumidityControl := TRUE;
        DehumidityControl := FALSE;
    (* Dehumidification control *)
    ELSIF HumiditySensor > HumidityHighLimit THEN
        HumidityControl := FALSE;
        DehumidityControl := TRUE;
    (* Within acceptable range *)
    ELSE
        HumidityControl := FALSE;
        DehumidityControl := FALSE;
    END_IF;
ELSE
    (* Oven inactive or baking complete - force all outputs OFF *)
    HeatingElement := FALSE;
    CoolingElement := FALSE;
    HumidityControl := FALSE;
    DehumidityControl := FALSE;
END_IF;
END_FUNCTION_BLOCK

FUNCTION_BLOCK TheaterControl
VAR_INPUT
    StartButton : BOOL;        (* Input for starting a performance *)
    StopButton : BOOL;         (* Input for stopping a performance *)
    SceneNumber : INT;         (* Input for selecting the scene or act *)
END_VAR
VAR_OUTPUT
    LightingControl : BOOL;    (* Output for controlling lighting *)
    SoundControl : BOOL;       (* Output for controlling sound *)
    PerformanceInProgress : BOOL; (* Indicator for an ongoing performance *)
END_VAR
VAR
    CurrentState : INT := 0;   (* 0=Idle, 1=Validate Scene, 2=Performance Active *)
    NextState : INT := 0;
END_VAR

(* State machine execution *)
CurrentState := NextState;

CASE CurrentState OF
    0: (* Idle State *)
        LightingControl := FALSE;
        SoundControl := FALSE;
        PerformanceInProgress := FALSE;

        IF StopButton THEN
            NextState := 0;
        ELSIF StartButton AND NOT PerformanceInProgress THEN
            NextState := 1;
        ELSE
            NextState := 0;
        END_IF;

    1: (* Validate Scene State *)
        (* Stop button has highest priority *)
        IF StopButton THEN
            NextState := 0;
        ELSIF (SceneNumber >= 1) AND (SceneNumber <= 3) THEN
            NextState := 2;
        ELSE
            (* Invalid scene number - return to idle *)
            NextState := 0;
        END_IF;

    2: (* Performance Active State *)
        LightingControl := TRUE;
        SoundControl := TRUE;
        PerformanceInProgress := TRUE;

        IF StopButton THEN
            NextState := 0;
        ELSE
            NextState := 2;
        END_IF;

    ELSE
        (* Fallback to idle state for safety *)
        NextState := 0;
END_CASE;

