IF B54_Closed AND ((B10_12_Closed AND B10_1_Closed) OR B10_2_Closed) THEN
    Point_1a := 0;
ELSE
    Point_1a := 138;
END_IF;

// Point_2a: B55 closed AND (B10_12 closed AND B10_1 closed) OR B10_2 closed
IF B55_Closed AND ((B10_12_Closed AND B10_1_Closed) OR B10_2_Closed) THEN
    Point_2a := 0;
ELSE
    Point_2a := 138;
END_IF;

// Point_3a: B56 closed AND (B10_12 closed AND B10_2 closed) OR B10_1 closed
IF B56_Closed AND ((B10_12_Closed AND B10_2_Closed) OR B10_1_Closed) THEN
    Point_3a := 0;
ELSE
    Point_3a := 138;
END_IF;

// Point_4a: B57 closed AND (B10_12 closed AND B10_2 closed) OR B10_1 closed
IF B57_Closed AND ((B10_12_Closed AND B10_2_Closed) OR B10_1_Closed) THEN
    Point_4a := 0;
ELSE
    Point_4a := 138;
END_IF;

END_FUNCTION_BLOCK

FUNCTION_BLOCK FB_CircuitControl
VAR_INPUT
    Reset_All_CB : BOOL;
    Current_Fault_on_TRSF1 : INT;
    Current_Fault_on_66BUS1 : INT;
END_VAR

VAR_OUTPUT
    Short_Circuit_TRSF1 : BOOL;
    Short_Circuit_66BUS : BOOL;
    Open_CB1_66KV : BOOL;
    Open_CB2_66KV : BOOL;
    Open_CB_TRSF1 : BOOL;
    Open_CB2_22KV : BOOL;
END_VAR

VAR
    Threshold500 : INT := 500;
    Prev_Open_CB2_22KV : BOOL;
    Prev_Open_CB1_66KV : BOOL;
    Prev_Open_CB_TRSF1 : BOOL;
    Temp_Open_CB2_22KV : BOOL;
    Temp_Open_CB1_66KV : BOOL;
    Temp_Open_CB_TRSF1 : BOOL;
END_VAR

(* a) Implement short circuit detection *)
Short_Circuit_66BUS := (Current_Fault_on_66BUS1 > Threshold500);
Short_Circuit_TRSF1 := (Current_Fault_on_TRSF1 > Threshold500);

(* b) Implement circuit breaker control logic *)

(* First pass: Initial calculations *)
Temp_Open_CB2_22KV := (NOT Reset_All_CB) AND (NOT Prev_Open_CB2_22KV) AND (
    (Open_CB1_66KV AND Open_CB_TRSF1) OR Short_Circuit_66BUS
);

Temp_Open_CB1_66KV := (NOT Reset_All_CB) AND (NOT Temp_Open_CB2_22KV) AND (
    (Prev_Open_CB1_66KV AND Open_CB_TRSF1) OR Short_Circuit_66BUS
);

Temp_Open_CB_TRSF1 := (NOT Reset_All_CB) AND (NOT Temp_Open_CB2_22KV) AND (
    (Temp_Open_CB1_66KV AND Prev_Open_CB_TRSF1) OR Short_Circuit_66BUS
);

Open_CB2_66KV := TRUE;

(* Second pass: Update based on new conditions *)
Temp_Open_CB2_22KV := Temp_Open_CB2_22KV OR (
    (NOT Reset_All_CB) AND (NOT Prev_Open_CB2_22KV) AND (
        (Open_CB2_66KV AND Temp_Open_CB1_66KV AND Temp_Open_CB_TRSF1) OR Short_Circuit_TRSF1
    )
);

Temp_Open_CB1_66KV := Temp_Open_CB1_66KV OR (
    (NOT Reset_All_CB) AND (NOT Temp_Open_CB2_22KV) AND (
        (Open_CB2_66KV AND Prev_Open_CB1_66KV AND Temp_Open_CB_TRSF1) OR Short_Circuit_TRSF1
    )
);

Temp_Open_CB_TRSF1 := Temp_Open_CB_TRSF1 OR (
    (NOT Reset_All_CB) AND (NOT Temp_Open_CB2_22KV) AND (
        (Open_CB2_66KV AND Temp_Open_CB1_66KV AND Prev_Open_CB_TRSF1) OR Short_Circuit_TRSF1
    )
);

(* Assign temporary values to outputs *)
Open_CB2_22KV := Temp_Open_CB2_22KV;
Open_CB1_66KV := Temp_Open_CB1_66KV;
Open_CB_TRSF1 := Temp_Open_CB_TRSF1;

(* Store previous states for next scan *)
Prev_Open_CB2_22KV := Open_CB2_22KV;
Prev_Open_CB1_66KV := Open_CB1_66KV;
Prev_Open_CB_TRSF1 := Open_CB_TRSF1;

(* Failsafe: If Reset_All_CB is TRUE, force all circuit breakers to FALSE *)
IF Reset_All_CB THEN
    Open_CB1_66KV := FALSE;
    Open_CB2_66KV := FALSE;
    Open_CB_TRSF1 := FALSE;
    Open_CB2_22KV := FALSE;
    Prev_Open_CB2_22KV := FALSE;
    Prev_Open_CB1_66KV := FALSE;
    Prev_Open_CB_TRSF1 := FALSE;
END_IF;

END_FUNCTION_BLOCK

FUNCTION_BLOCK FB_AdvancedCircuitBreakerControl
VAR_INPUT
    S_AL1_P_B1 : BOOL;
    S_AL1_P_B2 : BOOL;
    S_AL1_MCB : BOOL;
    MCB_BUSY : BOOL;
    MCB_ERROR : BOOL;
    S_AL1_MCBR : BOOL;
    MCBR_BUSY : BOOL;
    MCBR_ERROR : BOOL;
    S_AL1_P_B3 : BOOL;
    S_AL1_MCB2 : BOOL;
    S_AL1_MCBR2 : BOOL;
END_VAR

VAR_OUTPUT
    E_AL1_B1 : BOOL;
    PUWS_AL1_B1_PLUS : BOOL;
    PUWS_AL1_B1_RIGHT : BOOL;
    PAS_AL1_PLUS : BOOL;
    PAS_AL1_TURN : BOOL;
END_VAR

VAR
    PPAL1 : BOOL := 1;
    PP0 : BOOL := 1;
    PP1 : BOOL := 0;
    PP2 : BOOL := 0;
    PP3 : BOOL := 0;
    PP4 : BOOL := 0;
    MCB : BOOL := 1;
    PP5 : BOOL := 0;
    PP7 : BOOL := 0;
    PPL3 : BOOL := 0;
    PPL4 : BOOL := 0;
    MCBR : BOOL := 1;
    PPL5 : BOOL := 0;
    PPL7 : BOOL := 0;
    STABLE : BOOL := 0;
    MCB_CONTROL : BOOL;
END_VAR

STABLE := 0;
WHILE (STABLE = 0) DO
    STABLE := 1;

    IF (PP0 = 1) AND (NOT MCB_CONTROL) AND (NOT PP1) THEN
        PP0 := 0;
        PP1 := 1;
        STABLE := 0;
    END_IF;

    IF (PP1 = 1) AND S_AL1_P_B1 AND (NOT PP2) THEN
        PP1 := 0;
        PP2 := 1;
        STABLE := 0;
    END_IF;

    IF (PP2 = 1) AND S_AL1_P_B2 AND (NOT MCB_CONTROL) AND (NOT PP3) THEN
        PP2 := 0;
        PP3 := 1;
        STABLE := 0;
    END_IF;

    IF (PP2 = 1) AND S_AL1_P_B2 AND MCB_CONTROL AND (NOT PPL3) AND (NOT PP1) THEN
        PP2 := 0;
        PPL3 := 1;
        PP1 := 1;
        STABLE := 0;
    END_IF;

    IF (PP3 = 1) AND S_AL1_MCB AND (NOT PP4) AND (NOT PP1) THEN
        PP3 := 0;
        PP4 := 1;
        PP1 := 1;
        STABLE := 0;
    END_IF;

    IF (PP4 = 1) AND (MCB = 1) AND MCB_BUSY AND (NOT PP5) THEN
        PP4 := 0;
        MCB := 0;
        PP5 := 1;
        STABLE := 0;
    END_IF;

    IF (PP5 = 1) AND S_AL1_MCB2 AND (NOT PP7) AND (NOT MCB) THEN
        PP5 := 0;
        PP7 := 1;
        MCB := 1;
        STABLE := 0;
    END_IF;

    IF (PP7 = 1) AND S_AL1_P_B3 THEN
        PP7 := 0;
        STABLE := 0;
    END_IF;

    IF (PPL3 = 1) AND S_AL1_MCBR AND (NOT PPL4) THEN
        PPL3 := 0;
        PPL4 := 1;
        STABLE := 0;
    END_IF;

    IF (PPL4 = 1) AND (MCBR = 1) AND MCBR_BUSY AND (NOT PPL5) THEN
        PPL4 := 0;
        MCBR := 0;
        PPL5 := 1;
        STABLE := 0;
    END_IF;

    IF (PPL5 = 1) AND S_AL1_MCBR2 AND (NOT PPL7) AND (NOT MCBR) THEN
        PPL5 := 0;
        PPL7 := 1;
        MCBR := 1;
        STABLE := 0;
    END_IF;

    IF (PPL7 = 1) AND S_AL1_P_B3 THEN
        PPL7 := 0;
        STABLE := 0;
    END_IF;
END_WHILE;

IF (PP0 = 1) OR (PP1 = 1) THEN
    E_AL1_B1 := 1;
END_IF;

IF (PP3 = 1) THEN
    MCB_CONTROL := 1;
END_IF;

IF (PPL3 = 1) OR (PPL4 = 1) THEN
    PAS_AL1_PLUS := 1;
    PAS_AL1_TURN := 1;
END_IF;

IF (PPAL1 = 1) OR (PP2 = 1) THEN
    PUWS_AL1_B1_PLUS := 1;
END_IF;

IF (PP2 = 1) OR (PP3 = 1) OR (PPL3 = 1) THEN
    E_AL1_B1 := 0;
END_IF;

IF (PP0 = 1) OR (PP3 = 1) THEN
    MCB_CONTROL := 0;
END_IF;

IF (PP0 = 1) OR (PP3 = 1) OR (PP4 = 1) THEN
    PAS_AL1_PLUS := 0;
    PAS_AL1_TURN := 0;
END_IF;

IF (PPAL1 = 1) OR (PP2 = 1) THEN
    PUWS_AL1_B1_RIGHT := 0;
END_IF;

END_FUNCTION_BLOCK
